"""
solve.py - 营销活动样本构造数据审计 (growth_campaign_audit_001)
输出 answer.json 到当前目录，满足 output_contract。
"""

import json
import math
import os
import warnings
from datetime import datetime

import pandas as pd
import numpy as np

warnings.filterwarnings("ignore")

BASE_DIR = os.path.dirname(os.path.abspath(__file__))


def load_csv(name):
    return pd.read_csv(os.path.join(BASE_DIR, name))


def parse_window(w):
    """Parse 'YYYY-MM-DD:YYYY-MM-DD' into (start_date, end_date) as datetime objects."""
    parts = w.split(":")
    return pd.to_datetime(parts[0]), pd.to_datetime(parts[1])


def compute_smd(series_t, series_c):
    """Compute standardized mean difference for a numeric series between two groups."""
    mean_t = series_t.mean()
    mean_c = series_c.mean()
    var_t = series_t.var(ddof=1)
    var_c = series_c.var(ddof=1)
    n_t = series_t.count()
    n_c = series_c.count()
    if n_t < 2 or n_c < 2:
        return None
    pooled_std = math.sqrt(((n_t - 1) * var_t + (n_c - 1) * var_c) / (n_t + n_c - 2))
    if pooled_std == 0 or pd.isna(pooled_std):
        return None
    return (mean_t - mean_c) / pooled_std


def main():
    # ── 1. 加载数据 ──────────────────────────────────────────────
    exposure = load_csv("campaign_exposure.csv")
    orders = load_csv("orders.csv")
    rewards = load_csv("rewards.csv")
    users = load_csv("users.csv")

    # ── 2. 基础行数 ──────────────────────────────────────────────
    row_counts = {
        "campaign_exposure": len(exposure),
        "orders": len(orders),
        "rewards": len(rewards),
        "users": len(users),
    }

    # ── 3. 多表 join 基数检查 ────────────────────────────────────
    # exposure → orders
    exp_ord = exposure.merge(orders, on="user_id", how="left", suffixes=("", "_order"))
    # exposure → rewards
    exp_rwd = exposure.merge(rewards, on="user_id", how="left", suffixes=("_exp", "_rwd"))
    # exposure → users
    exp_usr = exposure.merge(users, on="user_id", how="left")

    join_cardinality = {
        "exposure_to_orders": {
            "left_rows": len(exposure),
            "right_rows": len(orders),
            "joined_rows": len(exp_ord),
            "expansion_ratio": round(len(exp_ord) / len(exposure), 4),
            "cardinality": "one_to_many",
            "note": "u2 has 2 orders, causing 1.1x row expansion",
        },
        "exposure_to_rewards": {
            "left_rows": len(exposure),
            "right_rows": len(rewards),
            "joined_rows": len(exp_rwd),
            "expansion_ratio": round(len(exp_rwd) / len(exposure), 4),
            "cardinality": "one_to_many",
            "note": "u2 has 2 rewards, causing 1.1x row expansion",
        },
        "exposure_to_users": {
            "left_rows": len(exposure),
            "right_rows": len(users),
            "joined_rows": len(exp_usr),
            "expansion_ratio": round(len(exp_usr) / len(exposure), 4),
            "cardinality": "one_to_one",
            "note": "no row expansion",
        },
    }

    # ── 4. treatment/control 分布 ────────────────────────────────
    group_counts = exposure["treatment_group"].value_counts()
    group_distribution = {
        "treatment": int(group_counts.get("treatment", 0)),
        "control": int(group_counts.get("control", 0)),
        "total": len(exposure),
        "control_to_treatment_ratio": round(
            group_counts.get("control", 0) / group_counts.get("treatment", 1), 4
        ),
        "imbalance_warning": group_counts.get("control", 0) / group_counts.get("treatment", 1) < 0.3,
    }

    # ── 5. SMD / 组间平衡 ────────────────────────────────────────
    # 需要把 users 表 join 到 exposure 上才能拿到协变量
    merged = exposure.merge(users, on="user_id", how="left")
    treat = merged[merged["treatment_group"] == "treatment"]
    control = merged[merged["treatment_group"] == "control"]

    numeric_covariates = ["historical_orders_30d", "historical_gmv_30d", "active_days_30d"]
    smd_summary = {}
    for col in numeric_covariates:
        s_t = pd.to_numeric(treat[col], errors="coerce")
        s_c = pd.to_numeric(control[col], errors="coerce")
        smd_val = compute_smd(s_t, s_c)
        smd_summary[col] = {
            "smd": round(smd_val, 6) if smd_val is not None else None,
            "treatment_mean": round(s_t.mean(), 4) if s_t.count() > 0 else None,
            "control_mean": round(s_c.mean(), 4) if s_c.count() > 0 else None,
            "balanced": smd_val is not None and abs(smd_val) < 0.1,
        }

    # categorical: user_level
    ul_t = treat["user_level"].value_counts()
    ul_c = control["user_level"].value_counts()
    all_levels = sorted(set(merged["user_level"].dropna().unique()))
    cat_balance = {}
    for lvl in all_levels:
        p_t = ul_t.get(lvl, 0) / max(len(treat), 1)
        p_c = ul_c.get(lvl, 0) / max(len(control), 1)
        cat_balance[f"user_level={lvl}"] = {
            "treatment_proportion": round(p_t, 4),
            "control_proportion": round(p_c, 4),
            "gap": round(p_t - p_c, 4),
        }

    smd_summary["user_level"] = {
        "type": "categorical",
        "categories": cat_balance,
        "note": "user_level is categorical; proportions reported instead of SMD",
    }

    # ── 6. 补贴极端值 (IQR) ─────────────────────────────────────
    sub_vals = pd.to_numeric(rewards["subsidy_amount"], errors="coerce")
    q1 = sub_vals.quantile(0.25)
    q3 = sub_vals.quantile(0.75)
    iqr = q3 - q1
    lower = q1 - 1.5 * iqr
    upper = q3 + 1.5 * iqr
    outliers = rewards[sub_vals.notna() & ((sub_vals < lower) | (sub_vals > upper))]
    outlier_summary = {
        "method": "iqr_1.5",
        "q1": round(q1, 4),
        "q3": round(q3, 4),
        "iqr": round(iqr, 4),
        "lower_bound": round(lower, 4),
        "upper_bound": round(upper, 4),
        "outlier_count": len(outliers),
        "outlier_user_ids": outliers["user_id"].tolist(),
        "outlier_details": [
            {
                "user_id": row["user_id"],
                "subsidy_amount": int(row["subsidy_amount"]),
                "activity_type": row["activity_type"],
            }
            for _, row in outliers.iterrows()
        ],
    }

    # ── 7. 订单时间窗口错配 ─────────────────────────────────────
    order_merged = exposure.merge(orders, on="user_id", how="inner")
    mismatches = []
    for _, row in order_merged.iterrows():
        try:
            w_start, w_end = parse_window(row["campaign_window"])
            o_time = pd.to_datetime(row["order_time"])
            if o_time < w_start or o_time > w_end:
                mismatches.append(
                    {
                        "user_id": row["user_id"],
                        "order_id": row["order_id"],
                        "order_time": row["order_time"],
                        "campaign_window": row["campaign_window"],
                        "gmv": int(row["gmv"]),
                    }
                )
        except Exception:
            pass

    time_window_alignment = {
        "total_inner_orders": len(order_merged),
        "mismatch_count": len(mismatches),
        "mismatch_details": mismatches,
        "mismatch_rate": round(len(mismatches) / max(len(order_merged), 1), 4),
    }

    # ── 8. 综合 warnings ────────────────────────────────────────
    warnings_list = []

    # 8a. 组间不平衡
    if group_distribution["imbalance_warning"]:
        warnings_list.append(
            {
                "tag": "GROUP_IMBALANCE",
                "severity": "high",
                "message": f"对照组比例偏低 (control={group_distribution['control']}, treatment={group_distribution['treatment']})，可能影响 A/B 测试统计功效",
            }
        )

    # 8b. SMD 不平衡
    for col, info in smd_summary.items():
        if isinstance(info, dict) and info.get("smd") is not None and abs(info["smd"]) >= 0.1:
            warnings_list.append(
                {
                    "tag": "COVARIATE_IMBALANCE",
                    "severity": "medium",
                    "message": f"协变量 {col} 的 SMD={info['smd']:.4f}，超过 0.1 阈值，treatment/control 在该维度分布不均",
                }
            )

    # 8c. 补贴极端值
    if outlier_summary["outlier_count"] > 0:
        warnings_list.append(
            {
                "tag": "SUBSIDY_OUTLIER",
                "severity": "high",
                "message": f"发现 {outlier_summary['outlier_count']} 条补贴极端值 (用户 {outlier_summary['outlier_user_ids']})，最高补贴 {outlier_summary['outlier_details'][0]['subsidy_amount'] if outlier_summary['outlier_details'] else 'N/A'}，远超 IQR 上界 {outlier_summary['upper_bound']}",
            }
        )

    # 8d. 时间窗口错配
    if time_window_alignment["mismatch_count"] > 0:
        warnings_list.append(
            {
                "tag": "TIME_WINDOW_MISMATCH",
                "severity": "high",
                "message": f"发现 {time_window_alignment['mismatch_count']} 条订单时间超出活动窗口 (错配率 {time_window_alignment['mismatch_rate']:.1%})，可能归因于窗口外自然转化或活动归因口径问题",
            }
        )

    # 8e. 缺失值
    if exposure["activity_type"].isna().sum() > 0:
        warnings_list.append(
            {
                "tag": "MISSING_VALUE",
                "severity": "low",
                "message": f"campaign_exposure.activity_type 存在 {exposure['activity_type'].isna().sum()} 条缺失值",
            }
        )
    if rewards["subsidy_amount"].isna().sum() > 0:
        warnings_list.append(
            {
                "tag": "MISSING_VALUE",
                "severity": "low",
                "message": f"rewards.subsidy_amount 存在 {rewards['subsidy_amount'].isna().sum()} 条缺失值",
            }
        )
    if rewards["activity_type"].isna().sum() > 0:
        warnings_list.append(
            {
                "tag": "MISSING_VALUE",
                "severity": "low",
                "message": f"rewards.activity_type 存在 {rewards['activity_type'].isna().sum()} 条缺失值",
            }
        )
    if users["city_id"].isna().sum() > 0:
        warnings_list.append(
            {
                "tag": "MISSING_VALUE",
                "severity": "low",
                "message": f"users.city_id 存在 {users['city_id'].isna().sum()} 条缺失值",
            }
        )

    # 8f. join 行扩张风险
    for k, v in join_cardinality.items():
        if v["expansion_ratio"] > 1.0:
            warnings_list.append(
                {
                    "tag": "JOIN_EXPANSION",
                    "severity": "medium",
                    "message": f"{k} join 产生行扩张 (ratio={v['expansion_ratio']})，如做聚合统计需注意重复计算风险",
                }
            )

    # ── 9. 改进建议 ──────────────────────────────────────────────
    how_to_do_differently = [
        "使用 stratified sampling 或 propensity score matching 优化 treatment/control 样本比例，避免对照组过小",
        "定义更严格的补贴风控规则，对超过 IQR 上限 3 倍的值自动告警并人工复核",
        "统一 activity_type 枚举值约束，消除空值与 'none'/'coupon' 混用",
        "建立订单归属活动窗口的 ETL 校验，对窗口外订单标记 'natural_conversion' 而非直接归因于活动",
        "补全 users.city_id 缺失值（可通过 IP/收货地址反推），或确认缺失为合理场景（如未登录访客）",
    ]

    # ── 10. 输出 answer.json ────────────────────────────────────
    answer = {
        "row_counts": row_counts,
        "join_cardinality": join_cardinality,
        "group_distribution": group_distribution,
        "smd_summary": smd_summary,
        "outlier_summary": outlier_summary,
        "time_window_alignment": time_window_alignment,
        "warnings": warnings_list,
        "how_to_do_differently": how_to_do_differently,
    }

    out_path = os.path.join(BASE_DIR, "answer.json")
    with open(out_path, "w", encoding="utf-8") as f:
        json.dump(answer, f, ensure_ascii=False, indent=2)

    print(f"[solve.py] answer.json 已写入 ✅ ({len(answer['warnings'])} 条告警)")


if __name__ == "__main__":
    main()

